#define TC1797_WRITE_PROT_N (sizeof(tc1797_write_prot)/sizeof(tc1797_write_prot[0]))
/* binary search (table is address-sorted); returns protected-bit mask or 0. */
static inline uint32_t tc1797_write_prot_mask(uint32_t addr)
{
    int lo = 0, hi = (int)TC1797_WRITE_PROT_N - 1;
    while (lo <= hi) {
        int mid = (lo + hi) >> 1;
        uint32_t a = tc1797_write_prot[mid].addr;
        if (a == addr) return tc1797_write_prot[mid].prot;
        if (a < addr) lo = mid + 1; else hi = mid - 1;
    }
    return 0;
}
